INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dc852117-5b52-4f85-9008-5108ee1e0b7e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Phoenix Input Validation — Ecto Changesets at the Controller Boundary$escape$,
  $escape$Phoenix's answer to boundary validation isn't middleware — it's Ecto changesets applied to embedded schemas directly in your controller or context. Define an embedded schema with typed fields, pipe params through `cast/3`, layer on `validate_required/2`, `validate_length/3`, `validate_format/3`, and reject invalid input before it touches your business logic. This gives you compile-time field awareness, automatic type coercion (string "42" → integer 42), and a structured error map that Phoenix renders cleanly via `Ecto.Changeset.traverse_errors/2`. Wire a `FallbackController` with `action_fallback MyAppWeb.FallbackController` and pattern-match on `{:error, %Ecto.Changeset{}}` to return consistent 422 JSON responses across every endpoint. Crucially, never trust `conn.params` directly — always `cast` against an explicit field allowlist. Fields not listed in `cast/3`'s third argument are silently dropped, giving you mass-assignment protection for free. For sanitization, run string fields through `String.trim/1` before casting or add a custom `validate_change` that rejects known injection patterns.$escape$,
  $escape$defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller
  action_fallback MyAppWeb.FallbackController

  @types %{name: :string, age: :integer, email: :string}

  defp validate_params(params) do
    {%{}, @types}
    |> Ecto.Changeset.cast(params, Map.keys(@types))
    |> Ecto.Changeset.validate_required([:name, :email])
    |> Ecto.Changeset.validate_length(:name, min: 2, max: 50)
    |> Ecto.Changeset.validate_format(:email, ~r/^[^\s]+@[^\s]+$/)
    |> Ecto.Changeset.apply_action(:validate)
  end

  def create(conn, params) do
    with {:ok, validated} <- validate_params(params) do
      render(conn, :show, user: validated)
    end
  end
end$escape$,
