INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '23489797-a397-4e0f-9fc8-e762d055e334',
  '00000000-0000-0000-0000-000000000001',
  $escape$Phoenix Configuration — Runtime vs Compile-Time and Secrets Done Right$escape$,
  $escape$Phoenix splits configuration into two distinct phases: compile-time (`config/config.exs`, `config/dev.exs`) and runtime (`config/runtime.exs`). The critical rule: all `System.get_env/1` calls for secrets and environment-specific values belong in `runtime.exs`, not `config.exs`. Reading env vars at compile time bakes values into the release binary, meaning your production Docker image would need to be rebuilt for every environment change.

In `runtime.exs`, use `System.fetch_env!/1` for required vars — it raises at startup if the var is missing, giving you a fast, explicit failure. For optional vars, use `System.get_env/2` with a default. Read config at runtime with `Application.fetch_env!/2` inside your modules.

For secrets in production releases, Phoenix 1.7+ generates `config/runtime.exs` with a `secret_key_base` block out of the box. Never hardcode this — run `mix phx.gen.secret` to generate a 64-byte value and inject it via `SECRET_KEY_BASE`. For database credentials, pass `DATABASE_URL` and let Ecto parse it via `Repo.config/0`.$escape$,
  $escape$# config/runtime.exs
import Config

if config_env() == :prod do
  database_url =
    System.fetch_env!("DATABASE_URL")

  config :my_app, MyApp.Repo,
    url: database_url,
    pool_size: String.to_integer(System.get_env("POOL_SIZE", "10"))

  secret_key_base =
    System.fetch_env!("SECRET_KEY_BASE")

  config :my_app, MyAppWeb.Endpoint,
    secret_key_base: secret_key_base
end$escape$,
  $escape$elixir$escape$,
